"use strict";parserFactory.register("b.faloo.com",()=>new FalooParser);class FalooParser extends Parser{constructor(){super(),this.minimumThrottle=2e3}async getChapterUrls(e){if(!e.querySelector(".DivVip"))return[...e.querySelectorAll("div.DivTable div div a")].map(e=>util.hyperLinkToChapter(e));let t=e.querySelector("div.DivTable:nth-child(3)");return util.hyperlinksToChapterList(t)}findContent(e){return e.querySelector(".noveContent")}extractTitleImpl(e){return e.querySelector("#novelName")}extractAuthor(e){let t=e.querySelector("a.fs14");return t?.textContent??super.extractAuthor(e)}extractLanguage(){return"Zh-CN"}extractSubject(e){return[...e.querySelectorAll("div.T-R-T-B2-Box1 a")].map(e=>e.textContent.trim()).join(", ")}extractDescription(e){return e.querySelector(".T-L-T-C-Box1").textContent.trim()}findChapterTitle(e){return e.querySelector(".c_l_title h1")}findCoverImageUrl(e){return e.querySelector(".imgcss").src}async fetchChapter(e){return(await HttpClient.wrapFetch(e,this.makeOptions())).responseXML}makeOptions(){return{makeTextDecoder:()=>new TextDecoder("gb2312")}}}